// Extract and store variables for use throughout the workflow
const item = $input.first().json;

return [{
  json: {
    execution_id: item.execution_id,
    callback_url: item.callback_url || null,
    original_script: item.script,
    target_scenes: item.config?.target_scenes || 0,
    style: item.config?.style || 'cinematic',
    language: item.config?.language || 'en',
    timestamp: new Date().toISOString()
  }
}];

// Parse the AI response and validate structure
const item = $input.first().json;

// Handle both Anthropic and OpenAI response formats
const response = item.body?.content?.[0]?.text ||
                 item.content?.[0]?.text ||
                 item.body?.choices?.[0]?.message?.content ||
                 item.choices?.[0]?.message?.content;

if (!response) {
  throw new Error('No content found in AI response');
}

let parsed;
try {
  // Extract JSON from response (handle markdown code blocks)
  const jsonMatch = response.match(/```json\n?([\s\S]*?)\n?```/) ||
                    response.match(/\{[\s\S]*\}/);
  const jsonStr = jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : response;
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error(`Failed to parse AI response as JSON: ${e.message}`);
}

// Validate required fields
const required = ['title', 'scenes', 'characters'];
for (const field of required) {
  if (!parsed[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Validate scenes
if (!Array.isArray(parsed.scenes) || parsed.scenes.length === 0) {
  throw new Error('Scenes must be a non-empty array');
}

// Validate characters
if (!Array.isArray(parsed.characters) || parsed.characters.length === 0) {
  throw new Error('Characters must be a non-empty array');
}

// Determine which provider was used
const isFromOpenAI = item.body?.choices !== undefined || item.choices !== undefined;
const provider = isFromOpenAI ? 'openai' : 'anthropic';

return [{
  json: {
    execution_id: $('Set Variables').item.json.execution_id,
    enhanced_script: parsed,
    structure: {
      scene_count: parsed.scenes.length,
      character_count: parsed.characters.length,
      estimated_duration: parsed.duration_estimate ||
        parsed.scenes.reduce((acc, s) => acc + (s.duration_seconds || 10), 0)
    },
    metadata: {
      original_length: $('Set Variables').item.json.original_script.length,
      enhanced_at: new Date().toISOString(),
      provider: provider
    }
  }
}];

